svg.script:
(() => {
  "use strict";
  const svg = document.getElementById("mini-stage");

  // ── confirmed 常量 ──
  const ROLL_PIVOT = { x: 187, y: 252 };   // 头 roll 轴 = 母版系脖根(sleep/peek/alert 同款)

  // ── mini-enter-sleep 可调参数(tuner state)──
  const state = {
    // ① 整体探入(slideDist=屏外起点偏移,横躺后母版 y+ = 屏幕水平外侧)
    slideDist: 188, slideDelay: 0.1, slideDur: 0.58,
    // ② 爪先探(爪头绝对偏移:快速冲到屏内+伸稍多 → 随身体回 rest=0)
    pawDur: 0.4, pawOver: 46, pawBack: 0.42,
    // ③ 头钻出洞(缩脖 rollDown → 抬头过冲"仰" rollOver → 落到睡姿耷拉 -tiltRest)
    rollDown: 20, rollOver: 12, headDelay: 0.3, headDur: 0.58,
    tiltRest: 7,             // 终点睡姿耷角 = mini-sleep sleep-head-tilt t=0 值(绕脖根落 -7)
    // ④ 醒→睡过渡(sleepP:0=睁眼母版眉微笑, 1=闭眼睡眉收口嘴),时机滑块
    sleepStart: 0.2, sleepDur: 0.5,
    browLift: 4, mouthInsetRest: 16,   // = mini-sleep 终点睡脸(逐字)
    // 软部件惯性
    tieLag: 3.0, glassLag: 4,
    speed: 1.0
  };

  // ── 时间线:入场过渡播一次 ≈ T_ENTER 停在睡姿(host 接手切 mini-sleep);tuner 加 T_TAIL 自动重播 ──
  const T_ENTER = 1.1, T_TAIL = 0.7, T_LOOP = T_ENTER + T_TAIL;
  const LOOP_MODE = /[?&]loop=1/.test(location.search);  // 默认播一次停睡姿(host 切 mini-sleep); ?loop=1 循环演示

  // ── 工具 ──
  function clamp(v, a, b) { return Math.max(a, Math.min(b, v)); }
  function lerp(a, b, t) { return a + (b - a) * t; }
  function smooth01(v) { const t = clamp(v, 0, 1); return t * t * (3 - 2 * t); }
  function easeOutCubic(v) { const t = clamp(v, 0, 1) - 1; return 1 + t * t * t; }
  function fmt(v) { return String(parseFloat(Number(v).toFixed(2))); }
  function setT(id, transform) {
    const node = svg.querySelector(`#${id}`);
    if (node) { if (transform) node.setAttribute("transform", transform); else node.removeAttribute("transform"); }
  }
  function setOp(id, v) {
    const node = svg.querySelector(`#${id}`);
    if (node) node.setAttribute("opacity", v);
  }

  // thinking 定稿闭嘴收口搬运(sleep/alert 同款 applyMouthInset)
  function applyMouthInset(inset) {
    ["mouth-left", "mouth-right"].forEach((id) => {
      const node = svg.querySelector(`#${id}`);
      if (!node || !node.getTotalLength) return;
      if (inset <= .01) {
        node.removeAttribute("stroke-dasharray");
        node.removeAttribute("stroke-dashoffset");
        return;
      }
      const length = node.getTotalLength();
      const visibleLength = Math.max(.1, length - inset);
      node.setAttribute("stroke-dasharray", `${fmt(visibleLength)} ${fmt(length + 24)}`);
      node.setAttribute("stroke-dashoffset", "0");
    });
  }

  // ── enter 时间线:返回各动作归一化进度 ──
  function enterAt(tSec) {
    const tt = LOOP_MODE ? clamp(tSec % T_LOOP, 0, T_ENTER) : Math.min(tSec, T_ENTER);
    const slideP = easeOutCubic(clamp((tt - state.slideDelay) / state.slideDur, 0, 1));
    const headP = clamp((tt - state.headDelay) / state.headDur, 0, 1);
    return { tt, slideP, headP };
  }

  // ── 爪头绝对偏移曲线(屏外 slideDist → 快速冲到 -pawOver 屏内稍多 → 回 rest 0)──
  function pawAbs(tt) {
    if (tt < state.pawDur) {
      return lerp(state.slideDist, -state.pawOver, easeOutCubic(tt / state.pawDur));
    }
    const back = clamp((tt - state.pawDur) / state.pawBack, 0, 1);
    return lerp(-state.pawOver, 0, smooth01(back));
  }

  // ── 头 roll 曲线(缩脖 rollDown → 抬头过冲到 -rollOver "仰" → 落到睡姿耷拉 -tiltRest)──
  function headRoll(headP) {
    if (headP <= 0) return state.rollDown;
    if (headP >= 1) return -state.tiltRest;
    if (headP < 0.62) {
      return lerp(state.rollDown, -state.rollOver, easeOutCubic(headP / 0.62));
    }
    return lerp(-state.rollOver, -state.tiltRest, smooth01((headP - 0.62) / 0.38));
  }

  // ── 醒→睡过渡进度(0=醒 1=睡),时机由 sleepStart/sleepDur 滑块定 ──
  function sleepAt(tt) {
    return smooth01((tt - state.sleepStart) / state.sleepDur);
  }
  function applySleep(sp) {
    const awakeOp = fmt(1 - sp), sleepOp = fmt(sp);
    // 眼:睁眼椭圆淡出 / 闭眼弧淡入
    setOp("left-eye", awakeOp); setOp("right-eye", awakeOp);
    setOp("sleep-left-eye-arc", sleepOp); setOp("sleep-right-eye-arc", sleepOp);
    // 眉:醒着 neutral 淡出 / 睡觉拱淡入 + 上移
    setOp("brows-awake", awakeOp); setOp("brows-asleep", sleepOp);
    const lift = state.browLift * sp;
    setT("brows-asleep", lift > .01 ? `translate(0 ${fmt(-lift)})` : "");
    // 嘴不在这里(全程睡嘴,不随 sleepP,见 apply)
  }

  // ── 渲染一帧(纯进度 e={tt,slideP,headP} → apply 全部 transform/opacity)──
  function apply(e) {
    // ① 整体探入:enter-slide 平移(母版 y = 屏幕水平;slideDist→0 = 从屏外进屏内 rest)
    const slideOff = state.slideDist * (1 - e.slideP);
    setT("enter-slide", slideOff > 0.1 ? `translate(0 ${fmt(slideOff)})` : "");

    // ② 爪先探:爪头绝对偏移 = pawAbs;相对身体的额外平移 = 绝对 - 身体 slideOff
    const reach = pawAbs(e.tt) - slideOff;
    setT("enter-hands-reach", Math.abs(reach) > 0.1 ? `translate(0 ${fmt(reach)})` : "");

    // ③ 头钻出洞:缩脖 → 抬头过冲 → 落睡姿耷拉(绕脖根 roll)
    const roll = headRoll(e.headP);
    setT("enter-head-roll", Math.abs(roll) > 0.02 ? `rotate(${fmt(roll)} ${ROLL_PIVOT.x} ${ROLL_PIVOT.y})` : "");

    // ④ 醒→睡:睁眼→闭眼 / 母版眉→睡眉(眼+眉过渡,嘴除外)
    applySleep(sleepAt(e.tt));
    // 嘴:全程睡觉小嘴(鹿鹿 2026-06-14:入睡过渡从头到尾收口,不出现微笑嘴)
    applyMouthInset(state.mouthInsetRest);

    // ⑤ 墨镜惯性:跟头钻出滞后微晃
    const glassPhase = clamp(e.tt - state.headDelay, 0, 99);
    const bob = (e.headP > 0 && e.headP < 1)
      ? -state.glassLag * Math.sin(2 * Math.PI * 2.2 * glassPhase) * Math.exp(-glassPhase * 3.0)
      : 0;
    setT("enter-glasses-lag", Math.abs(bob) > 0.02 ? `translate(0 ${fmt(bob)})` : "");

    // ⑥ 领带惯性:身体被拽进来,下摆滞后甩(阻尼振荡,软部件反应)
    const slidePhase = clamp(e.tt - state.slideDelay, 0, 99);
    const tieSway = (e.slideP > 0 && e.slideP < 1)
      ? state.tieLag * Math.sin(2 * Math.PI * 1.6 * slidePhase) * Math.exp(-slidePhase * 2.2)
      : 0;
    setT("tie-blade-sway", Math.abs(tieSway) > 0.02 ? `rotate(${fmt(tieSway)} 33.5 19)` : "");
  }

  // renderAt(tt): 纯进度渲染(不读 freeze/不取模),验证精确截任意 tt 用
  function renderAt(tt) {
    const slideP = easeOutCubic(clamp((tt - state.slideDelay) / state.slideDur, 0, 1));
    const headP = clamp((tt - state.headDelay) / state.headDur, 0, 1);
    apply({ tt, slideP, headP });
  }

  // ── 每帧 ──
  let paused = false;
  let t0 = performance.now();
  function frame(now) {
    if (!paused) {
      apply(enterAt((now - t0) / 1000 * state.speed));
      refreshJson();
    }
    requestAnimationFrame(frame);
  }

  function refreshJson() {} // 面板已剥离(导出无 tuner)

  requestAnimationFrame(frame);
  window.__miniEnterSleep = { state, enterAt, pawAbs, headRoll, sleepAt, renderAt, setPaused: (v) => { paused = v; }, T: { T_ENTER, T_TAIL, T_LOOP } };
})();
